def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        if bins[i] == 0:
            priorities[i] = np.inf
            continue
        ratio = item / bins[i]
        if ratio > 1:
            priorities[i] = ratio ** 3
        elif 0.5 < ratio <= 1:
            priorities[i] = (1 - ratio) * 10
        else:
            score = 0
            for j in range(1, 5):
                score += (ratio ** j) / j
            priorities[i] = score
        if bins[i] < item * 0.1:
            priorities[i] += 5
        if i % 2 == 0:
            priorities[i] *= 0.9
        else:
            priorities[i] *= 1.1
    max_priority = np.max(priorities[np.isfinite(priorities)])
    priorities[np.isinf(priorities)] = max_priority + 10
    return priorities
